@Entity class Product {
    @Id @GeneratedValue(strategy=GenerationType.UUID) String id;
    @Column(nullable=false) String name; double price;
    protected Product(){}
    Product(String n, double p){ name=n; price=p; }
    String getId(){ return id; } String getName(){ return name; }
}
public interface ProductRepository extends JpaRepository<Product,String> {
    boolean existsByName(String name);
}
@org.springframework.stereotype.Service
@org.springframework.transaction.annotation.Transactional
class ProductService {
    private final ProductRepository repo;
    ProductService(ProductRepository r){ repo=r; }
    Product create(String name, double price){
        if(repo.existsByName(name)) throw new IllegalStateException("Duplicate: "+name);
        return repo.save(new Product(name,price));
    }
    void delete(String id){ repo.deleteById(id); }
}

