import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.boot.test.web.client.TestRestTemplate;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.*;
import java.util.Map;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

@SpringBootTest(webEnvironment = SpringBootTest.WebEnvironment.RANDOM_PORT)
class ProductApiIntegrationTest {
    @Autowired TestRestTemplate rest;
    @Autowired ProductRepository repo;

    @BeforeEach void cleanDb() { repo.deleteAll(); }

    @Test
    void fullCrudLifecycle() {
        // CREATE:
        var createResp = rest.postForEntity("/api/products",
            Map.of("name","Mouse","price",799.0,"category","Electronics","stockQty",50),
            java.util.LinkedHashMap.class);
        assertEquals(HttpStatus.CREATED, createResp.getStatusCode());
        String id = (String) createResp.getBody().get("id");
        assertNotNull(id);

        // READ:
        var getResp = rest.getForEntity("/api/products/" + id, java.util.LinkedHashMap.class);
        assertEquals(HttpStatus.OK, getResp.getStatusCode());
        assertEquals("Mouse", getResp.getBody().get("name"));

        // DELETE:
        rest.delete("/api/products/" + id);

        // VERIFY 404:
        var notFound = rest.getForEntity("/api/products/" + id, String.class);
        assertEquals(HttpStatus.NOT_FOUND, notFound.getStatusCode());
    }
}

