        var cr = rest.postForEntity("/api/orders",Map.of("symbol","TCS","qty",10,"price",3890.0,"userId","U01"),java.util.LinkedHashMap.class);
        assertEquals(HttpStatus.CREATED, cr.getStatusCode());
        String id = (String) cr.getBody().get("id");
        var gr = rest.getForEntity("/api/orders/"+id, java.util.LinkedHashMap.class);
        assertEquals(HttpStatus.OK, gr.getStatusCode());
        assertEquals("TCS", gr.getBody().get("symbol"));
    }
